import com.smartquiz.config.DBConnection; import java.sql.*; public class CheckOptions { public static void main(String[] args) throws Exception { try (Connection conn = DBConnection.getConnection(); Statement stmt = conn.createStatement(); ResultSet rs = stmt.executeQuery("SELECT id, question_id, option_text FROM options LIMIT 10")) { while (rs.next()) { System.out.println("ID: " + rs.getInt("id") + ", QID: " + rs.getInt("question_id") + ", Text: " + rs.getString("option_text")); } } } }
